-spec solve(str) -> str.
solve(Str) ->
    process(Str, []).

process(<<"", _/binary>>, Result) ->
    Result;
process(<<C/binary, Rest/binary>>, Result) ->
    case C of
        $a =:= C -> process(Rest, [C | Result]);
        $* -> process(Rest, lists:sublist(Result, length(Result) - 1));
        $# -> process(Rest, Result ++ Result);
        $% -> process(Rest, lists:reverse(Result));
        _ -> process(Rest, [C | Result])
    end.
