solve(S) ->
    Processed = process_string(S, []),
    list_to_binary(Processed).

process_string(<<>>, Acc) ->
    Acc;
process_string(<<C:8, Rest:binary>>, Acc) ->
    case C of
        $a -> process_string(Rest, [C | Acc]);
        $* -> process_string(Rest, lists:sublist(Acc, length(Acc) - 1));
        $# -> Temp = lists:reverse(Acc), process_string(Rest, Temp ++ Temp);
        $% -> Temp = lists:reverse(Acc), process_string(Rest, Temp);
        _ -> process_string(Rest, [C | Acc])
    end.
